    for _ in range(8):
        m = y < 8.0
        s = s - tl.where(m, 1.0 / y, 0.0)
        y = tl.where(m, y + 1.0, y)

    # Asymptotic expansion for digamma at large y
    r = 1.0 / y
    r2 = r * r
    t2 = r2
    t4 = t2 * t2
    t6 = t4 * t2
    t8 = t4 * t4
