    ap = ap * (s + 3.0) * (s + 4.0)
    b = b / w2
    total += tl.where(b > 0.0, ap * b / 30240.0, 0.0)

    ap = ap * (s + 5.0) * (s + 6.0)
    b = b / w2
    total += tl.where(b > 0.0, ap * b / -1209600.0, 0.0)

