    b = b / w2
    total += tl.where(b > 0.0, ap * b / 7.47242496e10, 0.0)

    ap = ap * (s + 13.0) * (s + 14.0)
    b = b / w2
    total += tl.where(b > 0.0, ap * b / -2.950130727918164224e12, 0.0)

    ap = ap * (s + 15.0) * (s + 16.0)
    b = b / w2
    total += tl.where(b > 0.0, ap * b / 1.1646782814350067249e14, 0.0)

